window.__QUIZ_DATA__=[{"id":"objective>Geography>2008>1","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of IDUMUEGBU DISTRICT and use it to answer this question      The scale of the map as a linear scale is","images":["data:image/png;base64,","data:image/png;base64,","data:image/png;base64,","data:image/png;base64,","data:image/png;base64,"],"options":{"A":"","B":"","C":"","D":""},"answer":"B","explanation":"The scale of the map as a linear scale is C using the scale of 1cm on the map represent 200,000km on the ground (1 : 200,000)","marks":"1","difficulty":"2"},{"id":"objective>Geography>2008>2","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of IDUMUEGBU DISTRICT and use it to answer this question    If the map is reduced to half its size the new scale will be","images":["data:image/png;base64,"],"options":{"A":"1:600,000","B":"1:400,000","C":"1:200,000","D":"1:100,000"},"answer":"B","explanation":"The new scale of the map when reduced to half in representative function will be 1 : 400,000 (multiplying by two implies it reduction by 2).","marks":"1","difficulty":"2"},{"id":"objective>Geography>2008>3","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of IDUMUEGBU DISTRICT and use it to answer this question    The distance from Idumuegbu junction to Asa 'as the crow flies' is approximately","images":["data:image/png;base64,"],"options":{"A":"16km","B":"18km","C":"26km","D":"28km"},"answer":"A","explanation":"The distance from Idumuegbu junction to Asa \"as the crow flies\" is approximately 16km gotten by using a thread to measure the length from the map, placing it on a ruler for knowing the exact cm, then conversion based on the scale of the map.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2008>4","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of IDUMUEGBU DISTRICT and use it to answer this question    The area covered by Idumuegbu Housing Estate is approximately","images":["data:image/png;base64,"],"options":{"A":"72km2","B":"62km2","C":"50km2","D":"38km2"},"answer":"B","explanation":"Scale is 1 : 200,000 and 1cm = 2,000km  Sum of distances - width = 3.45cm  Length = 4.5cm  Equivalent ground distance : width = 3.45 \u00d7 2000  \u21d2 6900km    Length = 4.5 \u00d7 2000 = 9,000km    \u2234 The Area of Idumuegbu is a rectangle (L \u00d7 W)  \u21d2 6,900 \u00d7 9,000   \u2248 62km2","marks":"1","difficulty":"2"},{"id":"objective>Geography>2008>5","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of IDUMUEGBU DISTRICT and use it to answer this question    The feature 580 on the map represents","images":["data:image/png;base64,"],"options":{"A":"knick point","B":"confluence point","C":"packet station","D":"spot height"},"answer":"D","explanation":"The feature 580 on the map represents spot height which is an exact point on the map with an elevation recorded beside it that represents its height above a given datum.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2008>6","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of IDUMUEGBU DISTRICT and use it to answer this question    The highest contour line on the map is","images":["data:image/png;base64,"],"options":{"A":"500m","B":"600m","C":"650m","D":"700m"},"answer":"B","explanation":"The highest contour line on the map is showing 600m.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2008>7","subject":"Geography","year":"2008","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Study the map of IDUMUEGBU DISTRICT and use it to answer this question    The main occupation of the people living in the south eastern part of the map is mainly","images":["data:image/png;base64,"],"options":{"A":"trading","B":"fishing","C":"farming","D":"mining"},"answer":"C","explanation":"The main occupation of the people living in the south eastern part of the map is mainly farming due to the excess scattered cultivation and palm trees.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2008>8","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of IDUMUEGBU DISTRICT and use it to answer this question    The direction of Umudibiokwu from Tapa is","images":["data:image/png;base64,"],"options":{"A":"South-east","B":"South-west","C":"North-wards","D":"East-wards"},"answer":"B","explanation":"The direction of Umudibrokwu from Tapa is South-West.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2008>9","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of IDUMUEGBU DISTRICT and use it to answer this question    The feature marked Y can best be described as a/an","images":["data:image/png;base64,"],"options":{"A":"saddle","B":"knoll","C":"escarpment","D":"ridge"},"answer":"A","explanation":"The feature marked Y can best be described as a saddle which is a dip or low point between two areas of higher ground i.e a dip or break along a level ridge crest.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2008>10","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of IDUMUEGBU DISTRICT and use it to answer this question    The bearing of Osu from Umuogene is","images":["data:image/png;base64,"],"options":{"A":"288\u00b0","B":"280\u00b0","C":"266\u00b0","D":"252\u00b0"},"answer":"B","explanation":"The bearing of OSU from Umuogene is N10\u00b0W i.e 280\u00b0.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2008>11","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The earth lies between the","images":[],"options":{"A":"Mercury and the Venus","B":"Mars and the Jupiter","C":"Venus and the Mars","D":"Jupiter and the Pluto"},"answer":"C","explanation":"In the solar system, the order of the planets from the sun is Mercury, Venus, Earth, Mars, Jupiter, Saturn, Uranus, Neptune, and Pluto. Therefore, the Earth lies between Venus and Mars.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2008>12","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"When the moon comes in between the earth and the sun","images":[],"options":{"A":"eclipse of the moon occurs","B":"the length of the day varies","C":"a solar eclipse occurs","D":"the length of day increases"},"answer":"C","explanation":"When the moon comes in between the earth and the sun, it blocks the sun's light from reaching the earth. This phenomenon is known as a solar eclipse.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2008>13","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"How long does it take the Mercury to make a complete revolution?","images":[],"options":{"A":"88 days","B":"225 days","C":"365 1/4 days","D":"687 days"},"answer":"A","explanation":"Mercury, the planet closest to the sun, takes about 88 Earth days to complete one orbit around the sun. This period of time is known as a year on Mercury.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2008>14","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Which of the following is not a proof of the earth's sphericity?","images":[],"options":{"A":"Circumnavigation of the earth","B":"Deflection of winds","C":"Ship's visibility","D":"The circular horizon"},"answer":"B","explanation":"Deflection of winds is not a proof of the earth's sphericity. It is a phenomenon caused by the rotation of the Earth, known as the Coriolis effect. The Coriolis effect is the deflection of moving objects caused by the rotation of the Earth. As the Earth spins, the Coriolis effect causes the paths of moving objects to curve as seen by an observer on the Earth.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2008>15","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Which of the following is not a characteristic of lines of longitude? They","images":[],"options":{"A":"run from East to West","B":"converge at the poles","C":"run from north to south","D":"are used in calculating local time"},"answer":"A","explanation":"Lines of longitude, also known as meridians, do not run from East to West. They run from North to South and converge at the poles. They are used in calculating local time and determining the geographical position of a place in terms of east or west of the Prime Meridian.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2008>16","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"If the time at the Greenwich Meridian is 11.00am. What would the local time be at a place 75\u00b0W?","images":[],"options":{"A":"6.00 p.m","B":"5.00 p.m","C":"6.00 a.m","D":"5.00 a.m"},"answer":"C","explanation":"Localtime=\u03b8360\u00d724hrs  \u03b8 = 75\u00b0W  At 11:00am in the Greenwich Meridian  \u03b8360\u00d724=11hr  \u03b8 = 165\u00b0W  Since they are on the same long (165 - 75) = 90\u00b0  90360\u00d724=6hr  i.e the 6th hour of the day  \u21d2 6.00am","marks":"1","difficulty":"3"},{"id":"objective>Geography>2008>17","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : STATISTICAL MAPS AND DIAGRAMS","question":"MAP X: Population figure for regions A, B, C and D.  1 dot represents 10,000 persons    Use it to answer this question    What is the total population of Region A?","images":["data:image/png;base64,"],"options":{"A":"10,000","B":"15,000","C":"40,000","D":"45,000"},"answer":"C","explanation":"Total population of Region A  Recall, 1 dot represents 10,000 persons   Region A has 4 dots = 4 \u00d7 10,000  \u21d2 40,000 persons","marks":"1","difficulty":"1"},{"id":"objective>Geography>2008>18","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : STATISTICAL MAPS AND DIAGRAMS","question":"MAP X: Population figure for regions A, B, C and D.  1 dot represents 10,000 persons    Use it to answer this question  What is the total population of Region B and C?","images":["data:image/png;base64,"],"options":{"A":"100,000","B":"150,000","C":"160,000","D":"200,000"},"answer":"B","explanation":"Total population of Region B and C  Region B has 9 dots while Region C has 6 dots, (9 + 6) = 15 dots   15 \u00d7 10,000 = 150,000 persons","marks":"1","difficulty":"2"},{"id":"objective>Geography>2008>19","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : STATISTICAL MAPS AND DIAGRAMS","question":"MAP X: Population figure for regions A, B, C and D.  1 dot represents 10,000 persons    Use it to answer this question  What type of statistical method was used to represent the population in map X above?","images":["data:image/png;base64,"],"options":{"A":"Histogram","B":"Pie chart","C":"Proportional circle","D":"Dot map"},"answer":"D","explanation":"The statistical method used to represent the population in map X is the Dot Map.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2008>20","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The part of the earth where life exists is the","images":[],"options":{"A":"hydrosphere","B":"barysphere","C":"biosphere","D":"atmosphere"},"answer":"C","explanation":"The biosphere is the part of the earth where life exists. It is the global ecological system integrating all living beings and their relationships. This includes their interactions with the elements of the lithosphere (rocks), hydrosphere (water), and atmosphere (air).","marks":"1","difficulty":"1"},{"id":"objective>Geography>2008>21","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"A relative humidity of 100 per cent means that air is","images":[],"options":{"A":"unsaturated","B":"saturated","C":"dry","D":"moist"},"answer":"B","explanation":"A relative humidity of 100 percent means that air is saturated i.e the amount of water vapour in the air saturate.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2008>22","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The region on the earth's surface popularly referred to as the land of midnight sun is the","images":[],"options":{"A":"north of the Equator","B":"south of the Equator","C":"north of the Arctic circle","D":"north of the Tropic of Capricorn"},"answer":"C","explanation":"North of the Arctic circle is the region on the earth's surface popularly referred to as the land of midnight sun.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2008>23","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The earth is enveloped by a mixture of gases referred to as the","images":[],"options":{"A":"biosphere","B":"lithosphere","C":"mesosphere","D":"atmosphere"},"answer":"D","explanation":"The earth is enveloped by a mixture of gases referred to as the atmosphere (Nitrogen, oxygen, Carbondioxide, water vapour, noble gases, dust particles and other gas particles which are impure).","marks":"1","difficulty":"2"},{"id":"objective>Geography>2008>24","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Another name for the core of the earth is","images":[],"options":{"A":"lithosphere","B":"barysphere","C":"troposphere","D":"endosphere"},"answer":"B","explanation":"Another name for the core of the earth is barysphere. The barysphere is the deep interior of the earth, beneath the lithosphere and the asthenosphere, including the core.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2008>25","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Sedimentary rocks are usually","images":[],"options":{"A":"crystalline","B":"impervious","C":"stratified","D":"brittle"},"answer":"C","explanation":"Sedimentary rocks are usually stratified being accumulated in layers or strata, one on top of the other and after a long period of time, they become hardened by compression to form sedimentary rocks.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2008>26","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"All the following are processes of physical weathering except alternate","images":[],"options":{"A":"heating and cooling","B":"freezing and thawing","C":"wetting and drying","D":"oxidation and hydrolysis"},"answer":"D","explanation":"Physical weathering, also known as mechanical weathering, involves the breakdown of rocks and soils through direct contact with atmospheric conditions, such as heat, water, ice and pressure. The processes of physical weathering include heating and cooling, freezing and thawing, and wetting and drying. However, oxidation and hydrolysis are processes of chemical weathering, not physical weathering. Chemical weathering involves the change in the composition of rocks and soils due to reactions with atmospheric or biological chemicals.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2008>27","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"One of the features of a fold mountain is","images":[],"options":{"A":"graben","B":"anticline","C":"dyke","D":"horst"},"answer":"B","explanation":"Fold mountains are formed when two tectonic plates collide, causing the crust to buckle and fold. An anticline is a type of fold that is convex up and has its oldest beds at its core. It is a common feature of a fold mountain. On the other hand, a graben, a dyke, and a horst are not features of a fold mountain. A graben is a depressed block of the Earth's crust bordered by parallel faults, a dyke is a sheet of rock that formed in a fracture in a pre-existing rock body, and a horst is an elevated block of the Earth's crust that has been lifted by tectonic forces.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2008>28","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"Which of the following are water pollutants?","images":[],"options":{"A":"Aquatic animals","B":"Shrimps","C":"Dissolved fertilizers","D":"Water plants"},"answer":"A","explanation":"Dissolved fertilizers is a water pollutant by increasing the growth of algae which reduces the oxygen level in water causing death of aquatic organisms.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2008>29","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Which of these features is associated with wind erosion in the desert?","images":[],"options":{"A":"Zeugen","B":"Barchan","C":"Ripples","D":"Dunes"},"answer":"A","explanation":"Zeugen is associated with wind erosion in the desert. They are formed by the action of wind abrasion on alternating horizontal layers of hard and soft rocks.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2008>30","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : SOIL","question":"Which of the following is not a possible cause of soil erosion?","images":[],"options":{"A":"Afforestation","B":"Deforestation","C":"Bush burning","D":"Over-grazing"},"answer":"A","explanation":"Afforestation is not a cause of soil erosion but rather a method to prevent it. Afforestation refers to the process of planting trees in an area or converting a non-forest land into a forest. Trees help in holding the soil together with their roots, thereby reducing soil erosion.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2008>31","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"Which of the following is not a form of mass movement?","images":[],"options":{"A":"Landslide","B":"Earthquake","C":"Rockslide","D":"Talus creep"},"answer":"B","explanation":"An earthquake is not a form of mass movement. Mass movement refers to the movement of surface material caused by gravity. Examples include landslides, rockslides, and talus creep. An earthquake, on the other hand, is a sudden shaking of the earth's surface caused by the movement of tectonic plates and not by the movement of surface material.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2008>32","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"In the upper course of a river, all the following features can be found except","images":[],"options":{"A":"waterfall","B":"gorge","C":"ox-bow lake","D":"cataracts"},"answer":"C","explanation":"The features found in the upper course of a river are steep valley sides, interlocking spurs, rapids, gorges and water falls.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2008>33","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"A place where water issues out from the ground naturally is called a","images":[],"options":{"A":"pond","B":"spring","C":"stream","D":"river"},"answer":"B","explanation":"A spring is a point at which water flows from an aquifer to the Earth's surface. It is a component of the hydrosphere. It is different from a pond, stream, or river. A pond is a body of standing water, either natural or man-made, that is usually smaller than a lake. A river is a natural flowing watercourse, usually freshwater, flowing towards an ocean, sea, lake or another river. A stream is a small, narrow river.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2008>34","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"A stalagmite differs from a stalactite in that a stalagmite.","images":[],"options":{"A":"is thinner and longer than a stalactile","B":"starts from the roof of a cave","C":"is evaporated calcium carbonate","D":"starts from the floor of a cave"},"answer":"D","explanation":"Stalagmites and stalactites are both types of speleothems that are found in limestone caves. The difference between the two lies in the way they form. Stalactites hang from the ceiling of a cave and are formed by the deposition of calcium carbonate and other minerals, which is precipitated from mineralized water solutions. Stalagmites rise from the floor of a cave due to the dripping water from the cave roof that is rich in calcium carbonate and other minerals. Therefore, a stalagmite starts from the floor of a cave.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2008>35","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"\"It is crescentic or moon-shaped and occurs transversely to the direction of the prevailing wind,\" The above statement is a description of a","images":[],"options":{"A":"yardang","B":"barchan","C":"zeugen","D":"rock pedestal"},"answer":"B","explanation":"Barchan is a crescentic or moon-shaped and occurs transversely to the direction of the prevailing wind.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2008>36","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Isotherm is to temperature as __________ is to pressure.","images":[],"options":{"A":"isohaline","B":"isohel","C":"isoneph","D":"isobar"},"answer":"D","explanation":"Isotherms are lines on a map connecting points having the same temperature at a given time or on average over a given period. Similarly, isobars are lines on a weather map connecting points of equal atmospheric pressure. Isohaline refers to lines connecting points of equal salt concentration in the ocean, isohel refers to lines connecting points receiving equal amounts of sunshine, and isoneph refers to lines connecting points of equal cloud cover.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2008>37","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Which of the following did Koppen use to classify the climates of the world?","images":[],"options":{"A":"Temperature and humidity","B":"Temperature and wind","C":"Temperature and rainfall","D":"Rainfall and humidity"},"answer":"C","explanation":"Koppen climate classification is based on temperature and dryness (that is places associated with more rainfall and cold).","marks":"1","difficulty":"2"},{"id":"objective>Geography>2008>38","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"All the following are environmental hazards except","images":[],"options":{"A":"flooding","B":"vulcanicity","C":"afforestation","D":"deforestation"},"answer":"C","explanation":"Afforestation is not an environmental hazard as it is a way of balancing out the amount of carbondioxide in the atmosphere through photosynthesis.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2008>39","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL RESOURCES","question":"The resources of the atmosphere include all the following except","images":[],"options":{"A":"vegetation","B":"rain","C":"wind","D":"gases"},"answer":"A","explanation":"Vegetation is not a resource of the atmosphere. It is a resource of the biosphere. The atmosphere provides resources such as wind for wind power, gases for various industrial processes, and rain for water supply.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2008>40","subject":"Geography","year":"2008","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"If the total land area of a country is 24,000 square kilometres, and the population is 7,200,000, what is the population density of the country?","images":[],"options":{"A":"200 persons per km2","B":"300 persons per km2","C":"2000 persons per km2","D":"3000 persons per km2"},"answer":"D","explanation":"Populationdensity=Total populationTotal land area  =7,200,00024,000=3,000persons/km2","marks":"1","difficulty":"2"},{"id":"objective>Geography>2008>41","subject":"Geography","year":"2008","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Which of the following is not a major type of migration?","images":[],"options":{"A":"Rural-urban","B":"International","C":"Inter-community","D":"Urban-rural"},"answer":"C","explanation":"The major types of migration include rural-urban, urban-rural, and international. Inter-community migration is not considered a major type of migration because it involves movement within the same general area, rather than between different types of areas (rural to urban, urban to rural, or across international borders).","marks":"1","difficulty":"2"},{"id":"objective>Geography>2008>42","subject":"Geography","year":"2008","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Rural settlement types include all the following except","images":[],"options":{"A":"linear","B":"dormitory","C":"nucleated","D":"dispersed"},"answer":"B","explanation":"Rural settlement types include linear, nucleated, and dispersed settlements. A dormitory settlement is not a type of rural settlement. It refers to an area where people live but commute to work elsewhere, often in urban areas. This type of settlement can be found in both rural and urban settings.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2008>43","subject":"Geography","year":"2008","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"All the following activities belong to primary industries except","images":[],"options":{"A":"lumbering","B":"quarrying","C":"processing","D":"fishing"},"answer":"C","explanation":"Primary industries are those that involve the extraction of raw materials from the earth. This includes activities like lumbering, quarrying, and fishing. Processing, however, is a secondary industry activity because it involves transforming raw materials into finished or semi-finished goods.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2008>44","subject":"Geography","year":"2008","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"\"It is universal, and can reach almost every where.\" Which transport mode is being referred to?","images":[],"options":{"A":"Road","B":"Railway","C":"Ocean","D":"Ropeways"},"answer":"A","explanation":"The transport mode being referred to is Road transport. This is because road transport has a universal presence and can reach almost everywhere. It is the most commonly used mode of transport and is usually the most accessible, especially in rural areas.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2008>45","subject":"Geography","year":"2008","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"The busiest and most important ocean route in the world is the","images":[],"options":{"A":"Trans-pacific","B":"North Atlantic","C":"Cape route","D":"South Alantic"},"answer":"B","explanation":"The busiest and most important ocean route in the world is the North Atlantic route. This is due to the large volume of trade that takes place between North America and Europe, which are both highly industrialized regions with significant import and export activities.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2008>46","subject":"Geography","year":"2008","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Which of the following is not a contribution of transportation to economic development?","images":[],"options":{"A":"Decreased production","B":"Movement of people and commodities","C":"Diffusion of ideas","D":"National integration"},"answer":"A","explanation":"Transportation contributes to economic development in many ways, but it does not decrease production. In fact, it often increases production by facilitating the movement of goods and people, spreading ideas, and promoting national integration. Therefore, 'Decreased production' is not a contribution of transportation to economic development.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2008>47","subject":"Geography","year":"2008","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TOURISM","question":"Which of the following is not a favourable factor for tourism development in West Africa?","images":[],"options":{"A":"Highlands, rocks and beaches","B":"Abundance of wildlife","C":"Ineffective publicity","D":"Improved communication facilities"},"answer":"C","explanation":"Ineffective publicity is not a favourable factor for tourism development in West Africa. The other options like highlands, rocks and beaches, abundance of wildlife, and improved communication facilities are all attractions that can draw tourists. However, ineffective publicity can hinder the growth of tourism as it may not adequately promote these attractions to potential tourists.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2008>48","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Which of the following is not a feature of wave erosion?","images":[],"options":{"A":"Beach","B":"Arch","C":"Cliff","D":"Wave-cut platform"},"answer":"D","explanation":"Wave-cut platform is not among the features of wave erosion.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2008>49","subject":"Geography","year":"2008","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"Trees in a savanna region develop the following adaptations to enable them to survive the long dry season except","images":[],"options":{"A":"shallow roots","B":"long taproots","C":"thick barks","D":"thin leaves"},"answer":"A","explanation":"Trees in a savanna region does not develop shallow roots because its adaptability won't ensure survival during the long dry season.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2008>50","subject":"Geography","year":"2008","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"One of the major problems of manufacturing industries in Tropical Africa is","images":[],"options":{"A":"high demand for manufactured products","B":"inadequate raw materials","C":"high quality of industrial labour","D":"high cost of labour"},"answer":"B","explanation":"One of the major problems of manufacturing industries in Tropical Africa is inadequate raw materials.","marks":"1","difficulty":"3"}];